/**
 * Service Worker Code for Quick Local Development
 * Shared between quick serve and Vite plugin
 */

self.addEventListener('install', (event) => {
  console.log('[Quick Dev SW] Installed');
  self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  console.log('[Quick Dev SW] Activated');
  event.waitUntil(clients.claim());
});

// Allow pages to request control (needed after hard reload)
self.addEventListener('message', (event) => {
  if (event.data === 'claim') {
    clients.claim();
  }
});

async function getFileFromIDB(filename) {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open('QuickFiles', 1);
    request.onerror = () => reject(request.error);
    request.onsuccess = () => {
      const db = request.result;
      if (!db.objectStoreNames.contains('files')) {
        resolve(null);
        return;
      }
      const transaction = db.transaction(['files'], 'readonly');
      const store = transaction.objectStore('files');
      const getRequest = store.get(filename);
      getRequest.onsuccess = () => resolve(getRequest.result);
      getRequest.onerror = () => reject(getRequest.error);
    };
  });
}

self.addEventListener('fetch', (event) => {
  const url = new URL(event.request.url);

  // Special handling for OAuth initiate - use redirect instead of fetch
  if (url.pathname.startsWith('/api/auth/initiate') || url.pathname.startsWith('/api/auth/github/initiate') || url.pathname.startsWith('/api/auth/slack/initiate') || url.pathname.startsWith('/api/auth/shop/initiate')) {
    event.respondWith(
      Response.redirect('https://quick.shopify.io' + url.pathname + url.search, 307)
    );
    return;
  }

  // Proxy platform data files to production
  const platformFiles = ['/directory.json', '/users.json', '/usage.json'];
  if (platformFiles.includes(url.pathname)) {
    event.respondWith(
      fetch('https://quick.shopify.io' + url.pathname, { credentials: 'include', mode: 'cors' })
    );
    return;
  }

  // Redirect remote API calls to production (with credentials for IAP)
  const remoteAPIs = ['/api/ai/', '/api/dw/', '/api/slack/', '/api/http/', '/api/id', '/api/func/', '/api/auth/', '/api/sites/', '/api/mcp'];

  for (const apiPath of remoteAPIs) {
    if (url.pathname.startsWith(apiPath)) {
      const targetUrl = new URL('https://quick.shopify.io' + url.pathname + url.search);

      // Add returnTo only for auth status endpoints (so they can generate authUrl with returnTo)
      const isAuthStatus = url.pathname.match(/^\/api\/auth\/.*\/status$/) || url.pathname === '/api/auth/status';
      if (isAuthStatus && event.request.referrer && !targetUrl.searchParams.has('returnTo')) {
        targetUrl.searchParams.set('returnTo', event.request.referrer);
      }

      const options = {
        method: event.request.method,
        headers: event.request.headers,
        credentials: 'include',
        mode: 'cors'
      };

      // Add body for POST/PUT/PATCH requests
      if (event.request.method !== 'GET' && event.request.method !== 'HEAD') {
        options.body = event.request.body;
        options.duplex = 'half';
      }

      event.respondWith(
        fetch(targetUrl.toString(), options)
      );
      return;
    }
  }

  // Serve /files/* from IndexedDB (only for local dev server)
  if (url.hostname.includes('quick.localhost') && url.pathname.startsWith('/files/')) {
    event.respondWith(
      (async () => {
        const filename = decodeURIComponent(url.pathname.slice('/files/'.length));
        try {
          const fileData = await getFileFromIDB(filename);
          if (!fileData) {
            return new Response('File not found', {
              status: 404,
              headers: { 'Content-Type': 'text/plain' }
            });
          }
          return new Response(fileData.file, {
            status: 200,
            headers: {
              'Content-Type': fileData.mimeType,
              'Content-Length': fileData.size.toString(),
              'Cache-Control': 'public, max-age=0'
            }
          });
        } catch (error) {
          console.error('[Quick Dev SW] Error:', error);
          return new Response('Internal error', {
            status: 500,
            headers: { 'Content-Type': 'text/plain' }
          });
        }
      })()
    );
    return;
  }

  // Let everything else pass through
  event.respondWith(fetch(event.request));
});
